// ── Build the Forge confirmation + app-credentials email ──────────────
// Reads the student fields coming from "Map TeleCRM Fields" (full_name, email,
// phone, product…) and produces email_to / email_subject / email_html for the
// Gmail node. Password is the same Firstname@Forge! the app account uses.
//
// >>> EDIT these two links once: <<<
const GUIDE_URL    = 'https://YOUR-WELCOME-GUIDE-LINK';
const COMMUNITY_WA = 'https://chat.whatsapp.com/YOUR-COMMUNITY-LINK';
const APP_URL      = 'https://app.forgebylevelup.com/auth';

return $input.all().map(item => {
  const j = item.json;
  const fullName  = (j.full_name || '').trim();
  const firstRaw  = fullName.split(/\s+/)[0] || 'there';
  const firstName = firstRaw.charAt(0).toUpperCase() + firstRaw.slice(1).toLowerCase();
  const display   = fullName || firstName;
  const email     = j.email || '';
  const phone     = j.phone || '';
  const password  = `${firstName}@Forge!`;

  const html = `
<div style="font-family:-apple-system,Segoe UI,Arial,sans-serif;max-width:560px;margin:0 auto;color:#222;font-size:15px;line-height:1.7;">
  <p>Dear ${display},</p>
  <p>Welcome to <strong>The Forge Filmmaking Bootcamp!</strong> Congratulations — your seat is officially confirmed!</p>
  <p>Your confirmation payment has locked in your spot, and you're now part of a tribe of dreamers-turned-doers who are about to live, breathe, and create cinema together.</p>
  <p>At Forge, you don't just learn filmmaking — you live it. From script to screen, you'll write, direct, shoot, and edit your very own short film alongside passionate creators from across the country. Over fifteen days online and offline, you'll collaborate, experiment, and tell the stories you've always wanted to — and discover what it truly means to be a filmmaker.</p>

  <h3 style="margin:24px 0 8px;">Here's what happens next</h3>

  <p><strong>Your Welcome Guide</strong><br/>
  We've prepared a Welcome Guide that walks you through what to expect — from your daily schedule to a sneak peek of the experience that awaits. <a href="${GUIDE_URL}">Click here to view your Welcome Guide.</a> Trust us, it'll get you excited!</p>

  <div style="background:#f6f6f4;border:1px solid #e5e5e5;border-radius:10px;padding:16px 20px;margin:20px 0;">
    <p style="margin:0 0 8px;"><strong>Your Forge App access</strong></p>
    <p style="margin:0 0 10px;">The Forge App is your command center — learning, community, your roadmap and full journey, all in one place. Your account is ready:</p>
    <p style="margin:0;">🔗 Login: <a href="${APP_URL}">${APP_URL}</a><br/>
    📧 Email: <strong>${email}</strong><br/>
    🔑 Password: <strong>${password}</strong></p>
    <p style="margin:10px 0 0;font-size:13px;color:#555;">Prefer not to type a password? You can also log in with a one-time OTP sent to your registered phone number${phone ? ` (${phone})` : ''} — just tap &ldquo;Login with OTP&rdquo; on the login screen. You can change your password anytime after your first login.</p>
  </div>

  <p><strong>Join the Inner Circle</strong><br/>
  You're now part of the LevelUp Inner Circle — your private creator community to connect with mentors, alumni, and batchmates, plus online discussions, workshops, and invites to exclusive events and productions.</p>

  <p><strong>Balance Payment</strong><br/>
  Details about your balance payment, venue, and dates will be shared in the next email — stay tuned.</p>

  <p>Here's the link to the Community WhatsApp Group: <a href="${COMMUNITY_WA}">Join the Forge Community</a>. You'll also be added to your Edition WhatsApp Group closer to the program start.</p>

  <p>Any doubts about what's next — or anything at all — feel free to reach out:<br/>
  Email: forge@leveluplearning.in<br/>
  WhatsApp: Hiresh — 9840203604 (Program Lead) | Pranaush — 7397468193 (Head of Admissions)</p>

  <p>Our alumni call the Forge a once-in-a-lifetime experience, so brace yourself!</p>
  <p>And get ready to Lights, Camera, and Forge!</p>
  <p>Your Loudest Cheerleader,<br/>Team Forge by LevelUp Learning</p>
</div>`;

  return { json: {
    ...j,
    temp_password: password,
    email_to: email,
    email_subject: `Your Forge seat is confirmed, ${firstName}! 🎬`,
    email_html: html,
  }};
});
